const App = (function() {

    // ─── CONFIG ──────────────────────────────────────────────────────────────
    // App-wide constants. Nothing in here changes while the app is running.
    const Config = {
        // The badge types a task can cycle through. Each has a short letter label
        // shown on the coloured square in the UI. Pressing the badge rotates T→M→O→T.
        // ⚠️  BUG (V1): 'type-event' (E) is missing here — it exists in the latest
        //     version but was never added to V1. Fix: add { id:'type-event', label:'E' }.
        itemTypes: [{ id: 'type-task', label: 'T' }, { id: 'type-milestone', label: 'M' }, { id: 'type-outcome', label: 'O' }, { id: 'type-event', label: 'E' }],

        // Eight accent colours that new lanes get assigned in order.
        // Users can also manually rotate a lane's colour by clicking its colour dot.
        PAL: ['#4F8EF7', '#8B5CF6', '#10B981', '#F59E0B', '#EF4444', '#06B6D4', '#EC4899', '#84CC16'],

        defaultTheme: 'dotted', // Starting paper style: 'dotted' or 'lined'

        // The name used to open the browser's IndexedDB database.
        // The version suffix (V10) is bumped whenever the data shape changes,
        // which tells the browser to run a schema upgrade and avoid reading stale data.
        dbName: 'SwimlaneDB_V10',

        // Key used to read/write backup data in localStorage (the simpler storage API).
        // Only used as a last resort if IndexedDB isn't available, or for legacy migration.
        fallbackKey: 'SwimlaneFallback_V10',

        // Cap on how many day-rows are kept in the DOM at once.
        // Once this is exceeded, rows at the opposite end are quietly removed.
        // Prevents the page from slowing down after hours of scrolling.
        maxRenderedDays: 120
    };

    // ─── UTILS ───────────────────────────────────────────────────────────────
    // Stateless helper toolkit used by every other module.
    // Nothing in here reads or writes State — it is pure utility.
    const Utils = {
        // Generates a collision-safe unique ID string.
        // Used whenever a new lane, habit, item or note is created.
        // Prefers the browser's built-in crypto API; falls back to a timestamp+random
        // combo if crypto isn't available (very old browsers / some test runners).
        uuid: () => { try { return crypto.randomUUID(); } catch { return 'id_' + Date.now().toString(36) + Math.random().toString(36).substring(2, 15); } },

        // Turns a "YYYY-MM-DD" date string into a JavaScript Date set to midnight local time.
        // The 'T00:00:00' suffix forces local timezone instead of UTC, preventing off-by-one
        // day errors around midnight in non-UTC timezones.
        parseDate: (s) => new Date(s + 'T00:00:00'),

        // Turns a Date object back into a "YYYY-MM-DD" string using the local timezone.
        // padStart ensures single-digit months/days get a leading zero (e.g. "2025-01-05").
        toLocalISO: (d) => { const y = d.getFullYear(); const m = String(d.getMonth() + 1).padStart(2, '0'); const day = String(d.getDate()).padStart(2, '0'); return `${y}-${m}-${day}`; },

        // Returns today's Date object with the clock zeroed to midnight.
        // The setHours(0,0,0,0) call is critical — without it, comparisons like
        // "d < today" would be wrong for earlier hours of the current day.
        get today() { const d = new Date(); d.setHours(0,0,0,0); return d; },

        // Today as a "YYYY-MM-DD" string, ready for direct comparison against stored dateStr values.
        get todayStr() { return Utils.toLocalISO(this.today); },

        // Returns the number of whole days between a stored date and today.
        // Positive = future, 0 = today, negative = past. Divide by 86,400,000 (ms per day).
        // Used by the Horizon panel to display countdown labels like "5d" or "Past".
        getDiffDays: (dateStr) => { return Math.round((Utils.parseDate(dateStr) - Utils.today) / 86400000); },

        // Escapes HTML special characters in user-provided strings before injecting them
        // into innerHTML. Prevents XSS — e.g. a task named "<script>alert(1)</script>"
        // renders as visible text rather than executing as code.
        escape: (str) => String(str || '').replace(/[&<>"']/g, match => ({ '&': '&amp;', '<': '&lt;', '>': '&gt;', '"': '&quot;', "'": '&#39;' })[match])
    };

    // ─── STATE ───────────────────────────────────────────────────────────────
    // The single source of truth for the entire app.
    // Every visible element on screen is derived from this object.
    // It is saved to the Python backend on every change and reloaded on startup.
    //
    //  lanes        — the vertical swim-lane columns (title, colour, minimized flag)
    //  habits       — the daily habit tracker columns (title + unique id)
    //  items        — every task/milestone/outcome/event placed on the grid
    //  notes        — rich-text notes attached to each lane (opened via the 📝 button)
    //  habitChecks  — keyed by "YYYY-MM-DD", then habit id → true/false
    //  diary        — keyed by "YYYY-MM-DD" → freeform text for the diary column
    //  settings     — persistent UI preferences (theme, horizon mode, habit mode, etc.)
    let state = {
        version: 10,
        lanes: [{ id: 'l_1', title: 'Company', minimized: false, color: '#4F8EF7' }, { id: 'l_2', title: 'Home', minimized: false, color: '#8B5CF6' }, { id: 'l_3', title: 'Admin', minimized: false, color: '#10B981' }],
        habits: [ { id: 'h_1', title: 'Workout' }, { id: 'h_2', title: 'Read' }, { id: 'h_3', title: 'Diet' }, { id: 'h_4', title: 'Sleep' } ],
        items: [],
        notes: [],
        habitChecks: {},
        diary: {},
        settings: { theme: Config.defaultTheme, horizonMode: 'all', habitMode: 'streak', showAchievements: false, showHorizon: false }
    };

    // ─── UI STATE ────────────────────────────────────────────────────────────
    // Volatile UI-only state — never saved to the server.
    // Tracks which notes drawer is open and which note tab is selected.
    let uiState = { isNotesOpen: false, activeLaneNotes: null, activeNoteId: null };

    // Cached "today" string so the midnight rollover check (in Events.bind) can detect
    // when the calendar date has changed and re-render the today highlight.
    let currentUiToday = Utils.todayStr;

    // ─── VIRTUAL SCROLL BOOKKEEPING ──────────────────────────────────────────
    // dayMap:          Maps "YYYY-MM-DD" → the live DOM element for that row.
    //                  Used to patch individual cells without rebuilding the whole grid.
    // renderStartDate: The earliest date currently in the DOM.
    // renderEndDate:   The latest date currently in the DOM.
    // isVirtualizing:  Lock flag — prevents the IntersectionObserver from triggering
    //                  a second load batch while one is already in progress.
    const dayMap = new Map();
    let renderStartDate = null;
    let renderEndDate = null;
    let isVirtualizing = false;

    // ─── DOM ─────────────────────────────────────────────────────────────────
    // Named getters for the key structural DOM elements.
    // Using getters (not cached variables) means each access does a fresh getElementById
    // lookup — safe because elements are sometimes destroyed and recreated during
    // hardRebuild(). Never hold a reference to these across a rebuild.
    const DOM = {
        get header() { return document.getElementById('journal-header'); },
        get horizon() { return document.getElementById('journal-horizon'); },
        get body() { return document.getElementById('journal-body'); },
        get topSentinel() { return document.getElementById('top-sentinel'); },
        get bottomSentinel() { return document.getElementById('scroll-sentinel'); },
        get searchOverlay() { return document.getElementById('search-overlay'); },
        get searchInput() { return document.getElementById('search-input'); },
        get searchResults() { return document.getElementById('search-results'); },
        get onboarding() { return document.getElementById('onboarding-overlay'); },
        get importUpload() { return document.getElementById('import-upload'); },
        get notesOverlay() { return document.getElementById('notes-overlay'); },
        get notesDrawer() { return document.getElementById('notes-drawer'); },
        get notesLaneTitle() { return document.getElementById('notes-drawer-lane-title'); },
        get notesTabs() { return document.getElementById('notes-tabs'); },
        get noteEditor() { return document.getElementById('note-editor'); },
        get noteEmptyState() { return document.getElementById('note-empty-state'); },
        get noteTitleInput() { return document.getElementById('note-title-input'); },
        get noteBodyInput() { return document.getElementById('note-text-input'); },
        get toast() { return document.getElementById('undo-toast'); }
    };

    // ─── EVENTBUS ─────────────────────────────────────────────────────────────
    // A lightweight Publish / Subscribe message bus that decouples Actions from Render.
    //
    // How it works:
    //   1. Render.init() calls EventBus.on('someEvent', handler) to register listeners.
    //   2. Actions call EventBus.emit('someEvent', payload) after mutating State.
    //   3. The bus calls every registered handler — Render reacts without Actions needing
    //      to know anything about the DOM.
    //
    // clear() is called at the start of hardRebuild() to flush stale listeners before
    // Render.init() re-registers them, preventing duplicate handler accumulation.
    const EventBus = {
        listeners: {},
        on(event, cb) { if(!this.listeners[event]) this.listeners[event] = []; this.listeners[event].push(cb); },
        off(event, cb) { if(this.listeners[event]) this.listeners[event] = this.listeners[event].filter(l => l !== cb); },
        clear() { this.listeners = {}; },
        emit(event, data) { if(this.listeners[event]) this.listeners[event].forEach(cb => cb(data)); }
    };

    // ─── UNDO ─────────────────────────────────────────────────────────────────
    // Snapshot-based undo. Before any destructive action, snap() deep-clones the
    // entire State object and pushes it onto the stack (max 20 entries — the oldest
    // is dropped when the stack fills up to keep memory bounded).
    //
    // perform() pops the last snapshot, replaces the live State with it, saves to the
    // server, and triggers a full DOM rebuild — effectively rolling the app back in time.
    //
    // showToast() briefly displays a notification strip at the top of the screen so
    // the user can see what was undone.
    let undoTimer;
    const Undo = {
        stack: [], max: 20,
        // INPUT: label — human-readable name of the action being snapshotted (e.g. 'Add Lane')
        // ALGO:  deep-clone State via JSON round-trip (cheap and reliable for plain objects)
        // OUTPUT: new entry pushed onto stack; oldest entry trimmed if over limit
        snap(label = 'Action') {
            this.stack.push({ label, stateData: JSON.parse(JSON.stringify(state)) });
            if(this.stack.length > this.max) this.stack.shift();
        },
        // INPUT: none
        // ALGO:  pop last snapshot, overwrite live State, persist, rebuild UI
        // OUTPUT: app visually rolls back to the previous state; toast shown
        perform() {
            if(!this.stack.length) return;
            const snap = this.stack.pop();
            state = snap.stateData;
            Store.save(); applySettings(); Render.hardRebuild();
            this.showToast('Undid: ' + snap.label);
        },
        showToast(msg) {
            document.getElementById('undo-msg').innerText = msg;
            DOM.toast.classList.add('is-active');
            clearTimeout(undoTimer); undoTimer = setTimeout(() => DOM.toast.classList.remove('is-active'), 3500);
        }
    };

    // ─── STORE ────────────────────────────────────────────────────────────────
    // Handles all persistence. V1 uses a Python backend server as primary storage.
    // On startup, Store tries to load from that server. If the server returns empty
    // data, it checks for legacy client-side data (IndexedDB / localStorage) left over
    // from an older version, migrates it to the server, and then clears the local copy.
    //
    // Save path: every mutation calls debouncedSave() → Store.save() → POST /api/state
    // Load path: bootstrap → Store.init() (opens IndexedDB for migration check) →
    //            Store.load() (fetches /api/state, falls back to legacy data if server fails)
    const Store = {
        useIDB: false, db: null,
        init() {
            // Keep IndexedDB init to check for legacy client data to migrate
            return new Promise((resolve) => {
                try {
                    if (!window.indexedDB) return resolve();
                    const req = indexedDB.open(Config.dbName, 1);
                    req.onupgradeneeded = e => { e.target.result.createObjectStore('state'); };
                    req.onsuccess = e => { this.db = e.target.result; this.useIDB = true; resolve(); };
                    req.onerror = e => { resolve(); };
                } catch (e) { resolve(); }
            });
        },
        async load() {
            // 1. Check for legacy client-side data to migrate
            let legacyData = null;
            try {
                legacyData = await new Promise(resolve => {
                    if (this.useIDB && this.db) {
                        const tx = this.db.transaction('state', 'readonly');
                        const req = tx.objectStore('state').get('appData');
                        req.onsuccess = () => resolve(req.result);
                        req.onerror = () => resolve(this.loadFallbackLegacy());
                    } else {
                        resolve(this.loadFallbackLegacy());
                    }
                });
            } catch(e) {
                console.warn("Legacy load failed:", e);
            }

            // 2. Fetch active state from the Python backend server
            try {
                const response = await fetch('/api/state');
                if (response.ok) {
                    const serverData = await response.json();
                    if (serverData && Object.keys(serverData).length > 0) {
                        // Backend database is initialized; load server state
                        this.hydrate(serverData);
                        console.log("Journal loaded successfully from backend database.");
                    } else if (legacyData && Object.keys(legacyData).length > 0) {
                        // Backend database is empty, but legacy local data exists: bootstrap backend
                        console.log("Bootstrapping backend database with legacy local data...");
                        this.hydrate(legacyData);
                        await this.saveToServer(legacyData);

                        // Clean up legacy local storage after successful bootstrap
                        this.clearLegacy();
                    } else {
                        console.log("No data found on backend or locally. Starting fresh.");
                    }
                } else {
                    console.error("Backend returned error status:", response.status);
                    if (legacyData) this.hydrate(legacyData);
                }
            } catch (e) {
                console.error("Failed to connect to backend server. Falling back to local data.", e);
                if (legacyData) this.hydrate(legacyData);
            }
        },
        loadFallbackLegacy() {
            try {
                const raw = localStorage.getItem(Config.fallbackKey);
                return raw ? JSON.parse(raw) : null;
            } catch(e) {
                return null;
            }
        },
        clearLegacy() {
            try {
                localStorage.removeItem(Config.fallbackKey);
                if (this.useIDB && this.db) {
                    const tx = this.db.transaction('state', 'readwrite');
                    tx.objectStore('state').delete('appData');
                }
            } catch(e) {
                console.warn("Could not clear legacy local storage:", e);
            }
        },
        // INPUT: data — a raw JSON object from the server or local storage
        // ALGO:  Merges loaded data into the live State object, handling two legacy
        //        data formats. Old format stored habits as plain strings (["Workout", ...]);
        //        new format stores objects ({id, title}). The if-branch converts old → new.
        //        Items are filtered to discard any with missing required fields (defensive).
        // OUTPUT: live `state` is populated ready for Render to consume
        hydrate(data) {
            if(!data) return;
            state.lanes = data.lanes || state.lanes;
            state.lanes.forEach((l, i) => { if(!l.color) l.color = Config.PAL[i % Config.PAL.length]; });
            state.diary = data.diary || {};
            state.notes = data.notes || [];
            state.settings = { ...state.settings, ...(data.settings || {}) };
            state.items = (data.items || []).filter(i => i.id && i.dateStr && i.laneId && i.type);

            if (data.habits && typeof data.habits[0] === 'string') {
                // Legacy format: habits were stored as plain strings, not objects.
                // Convert and remap habitChecks keys from numeric index to the new id format.
                state.habits = data.habits.map((h, i) => ({ id: 'h_' + i, title: h }));
                Object.keys(data.habitChecks || {}).forEach(date => {
                    const newChecks = {}; Object.keys(data.habitChecks[date]).forEach(oldIdx => { newChecks['h_' + oldIdx] = data.habitChecks[date][oldIdx]; });
                    state.habitChecks[date] = newChecks;
                });
            } else {
                state.habits = data.habits || state.habits;
                state.habitChecks = data.checks || data.habitChecks || {};
            }
        },
        async save() {
            try {
                await this.saveToServer(state);
            } catch (e) {
                console.error("Autosave to backend failed:", e);
            }
        },
        async saveToServer(stateData) {
            const response = await fetch('/api/state', {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/json'
                },
                body: JSON.stringify(stateData)
            });
            if (!response.ok) {
                throw new Error(`Server returned response code: ${response.status}`);
            }
        }
    };

    // ─── DEBOUNCED SAVE ───────────────────────────────────────────────────────
    // Every keystroke in a text input would trigger a network request if we saved
    // immediately. Instead we reset a 300ms timer on each call — only when typing
    // pauses for 300ms does the actual POST /api/state fire.
    let saveTimer;
    const debouncedSave = () => { clearTimeout(saveTimer); saveTimer = setTimeout(() => Store.save(), 300); };

    // ─── APPLY SETTINGS ───────────────────────────────────────────────────────
    // Syncs the <body> element's CSS class with the current settings.
    // Changing body's class switches the CSS background pattern (dotted vs lined paper)
    // and toggles the "show past items" visibility rule.
    // Called on startup and whenever settings change.
    function applySettings() {
