// ─── RENDER ───────────────────────────────────────────────────────────────
// Turns State into visible HTML. Render never mutates State — it only reads it.
// Methods are called either directly (init, hardRebuild) or via EventBus listeners
// that Actions fire after each mutation.
//
// Sub-methods and what they own:
//   init()            — registers all EventBus listeners; called once on startup
//   hardRebuild()     — tears down and rebuilds the full DOM (used after structural changes)
//   gridCSS()         — writes a <style> tag with the CSS Grid column template
//   header()          — renders the sticky top header row (controls + lane headers + habits)
//   horizon()         — renders the collapsible Horizon panel shell
//   horizonData()     — fills the Horizon panel with current milestone/outcome/event data
//   syncHorizonHeight — snaps the Horizon panel height to the grid baseline
//   buildDayBlock()   — creates a single day-row DOM element (but doesn't add items yet)
//   trackContent()    — fills the item cells inside a day-row for a specific date
//   itemHTML()        — returns the inner HTML for a single task/milestone/event element
//   habitStats()      — updates the streak/total count badges above each habit column
//   updateDayToggles()— shows/hides the row collapse arrow; updates countdown labels
//   updateProgress()  — fills the thin progress bar on each day's date label
//   notesDrawerUI()   — renders the full notes side drawer
//   notesDrawerTabsOnly() — re-renders only the tab strip (faster than full drawer)
//   applyScrollFilter()   — shows/hides Horizon entries based on scroll position
const Render = {
    init() {
        EventBus.clear();
        this.gridCSS(); this.header(); this.horizon();

        BusWrap('structureChanged', () => this.hardRebuild());
        BusWrap('settingsChanged', () => { applySettings(); this.header(); this.horizonData(); });
        BusWrap('horizonToggled', () => {
            const btn = document.querySelector('[data-action="toggleHorizon"]');
            if(btn) btn.classList.toggle('active', state.settings.showHorizon);
            DOM.horizon.classList.toggle('is-expanded', state.settings.showHorizon);

