        // ─── VIRTUALSCROLL ────────────────────────────────────────────────────────
        // Keeps memory and paint cost low by only rendering ~120 day-rows at a time.
        //
        // How it works:
        //   - Two invisible sentinel <div>s (top and bottom) sit just outside the rendered range.
        //   - IntersectionObserver fires whenever either sentinel enters the viewport.
        //   - loadForward() / loadBackward() add 30 more rows on the relevant side, then
        //     cleanupTop() / cleanupBottom() prune rows from the opposite side to stay within
        //     Config.maxRenderedDays. Page scroll position is corrected so the user doesn't jump.
        //   - seekToDate() handles "Today" button and Horizon click-throughs — if the target
        //     date is already in the DOM it scrolls to it; otherwise it rebuilds the window
        //     centred on that date.
        //   - isVirtualizing lock prevents the observer from firing a second batch while one
        //     is already being appended to the DOM.
        const VirtualScroll = {
            pendingForward: false, pendingBackward: false,
            init() {
---
        // ─── DRAGDROP ─────────────────────────────────────────────────────────────
        // Wraps the SortableJS library (loaded via CDN) to enable drag-and-drop reordering
        // of items across any track on any day — including the Horizon overdue bins.
        //
        // Each track element gets its own Sortable instance, stored on track._sortable so
        // it can be destroyed before a trackContent() refresh prevents double-initialisation.
        //
        // The drag handle is the coloured type-badge square — users grab it to move items.
        // The 'group: matrix' setting allows items to move between different Sortable instances
        // (i.e. across lanes and across day rows), not just reorder within one list.
        const DragDrop = {
            // INPUT: trackEl — a .track DOM element to enable drag-drop on
            // ALGO:  Only creates a new Sortable if one doesn't already exist on the element.
            //        onEnd fires after a successful drop: finds the destination day-row, reads
---
        // ─── SEARCH ───────────────────────────────────────────────────────────────
        // Ctrl+K (or Cmd+K on Mac) command palette. Searches task text and diary entries,
        // shows the top 15 matches sorted by date (newest first), and navigates to the
        // matching day-row when a result is clicked.
        // Minimum 2 characters before searching to avoid flooding results with single-letter hits.
        const Search = {
            // INPUT: none; wires up keyboard and overlay click listeners
            // ALGO:  Debounces the search input 200ms to avoid searching on every keystroke.
            //        Ctrl+K toggles the search overlay open/closed; Escape closes it.
            //        Clicking outside the search modal (on the overlay backdrop) also closes it.
            // OUTPUT: event listeners registered; Search is ready to use
            init() {
                let searchTimer;
                DOM.searchInput.addEventListener('input', (e) => { clearTimeout(searchTimer); searchTimer = setTimeout(() => this.query(e.target.value), 200); });
---
        // ─── EVENTS ───────────────────────────────────────────────────────────────
        // Single global event listener hub using the event-delegation pattern.
        // Instead of attaching a listener to every button, one listener sits on `document`
        // and checks what was clicked. This scales to any number of dynamically added items.
        //
        // Routing works via `data-action` attributes:
        //   HTML:       <div data-action="addLane">+</div>
        //   JS picks up: btn.dataset.action === 'addLane' → calls Actions.addLane()
        //
        // Also handles: input changes, context-menu (right-click to complete),
        //               double-tap to complete on mobile, keyboard shortcuts (Ctrl+Z undo,
        //               Enter to add next task, Backspace-on-empty to delete),
        //               paste sanitisation, midnight date-change rollover check.
        const Events = {
            bind() {
                // Flush any pending debounced save before the tab closes or is hidden.
                window.addEventListener('beforeunload', () => { clearTimeout(saveTimer); Store.save(); });
---
        // ─── BOOTSTRAP ────────────────────────────────────────────────────────────
        // App entry point — called once via App.init() at the bottom of the script.
        // Startup sequence:
        //   1. Store.init()      — opens IndexedDB (checks for legacy data to migrate)
        //   2. Store.load()      — fetches saved state from the Python backend; falls back
        //                          to local legacy data if the server is unreachable
        //   3. applySettings()   — applies the loaded theme class to <body>
        //   4. Render.init()     — builds the header, horizon shell, registers EventBus listeners
        //   5. VirtualScroll.init() — sets up IntersectionObserver, renders first 60 day-rows
        //   6. Search.init()     — wires Ctrl+K search overlay
        //   7. Events.bind()     — attaches all global DOM event listeners
        //   8. Onboarding check  — shows tutorial overlay for first-time users
        //   9. Scroll to today   — smooth-scrolls to the today row on load
        async function bootstrap() {
            try { await Store.init(); await Store.load(); } catch(e) { console.error("Boot Failed", e); }
            applySettings(); Render.init(); VirtualScroll.init(); Search.init(); Events.bind();
            if (!localStorage.getItem('swimlane_onboarded')) DOM.onboarding.classList.add('is-active');

