// ─── BOOTSTRAP ────────────────────────────────────────────────────────────
// App entry point — called once via App.init() at the bottom of the script.
// Startup sequence:
//   1. Store.init()         — opens IndexedDB
//   2. Store.load()         — reads saved state; falls back to localStorage
//   3. applySettings()      — applies the loaded theme class to <body>
//   4. Render.init()        — builds the header, horizon shell, registers EventBus listeners
//   5. VirtualScroll.init() — sets up IntersectionObserver, renders first 60 day-rows
//   6. Search.init()        — wires Ctrl+K search overlay
//   7. Events.bind()        — attaches all global DOM event listeners
//   8. Onboarding check     — shows tutorial overlay for first-time users
//   9. Scroll to today      — smooth-scrolls to the today row on load
async function bootstrap() {
    try { await Store.init(); await Store.load(); } catch(e) { console.error("Boot Failed", e); }

